#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 50000
#define MAX_M 20
#define MAX_K 20
#define MAX_PACKS 1000000000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int packs[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &packs[i]);
        }
        qsort(packs, N, sizeof(int), compare);
        long long min_candies = -1;
        for (int mask = 0; mask < (1 << N); mask++) {
            int count = 0;
            long long total_candies = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    count++;
                    total_candies += packs[i];
                }
            }
            if (count == M && total_candies % K == 0) {
                if (min_candies == -1 || total_candies < min_candies) {
                    min_candies = total_candies;
                }
            }
        }
        printf("%lld\n", min_candies);
    }
    return 0;
}

