public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            int K = scanner.nextInt();
            int[] packs = new int[N];
            for (int i = 0; i < N; i++) {
                packs[i] = scanner.nextInt();
            }
            Arrays.sort(packs);
            long min_candies = -1;
            for (int mask = 0; mask < (1 << N); mask++) {
                int count = 0;
                long total_candies = 0;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        count++;
                        total_candies += packs[i];
                    }
                }
                if (count == M && total_candies % K == 0) {
                    if (min_candies == -1 || total_candies < min_candies) {
                        min_candies = total_candies;
                    }
                }
            }
            System.out.println(min_candies);
